{
  "sentences": [
    {
      "text": "你為什麼不想吃？",
      "pinyin": "Nǐ wèishénme bù xiǎng chī?",
      "pinyin_numeric": "ni3 wei4 shen2 me0 bu4 xiang3 chi1",
      "translation_en": "Why don't you want to eat?",
      "translation_ko": "왜 먹고 싶지 않으세요?"
    },
    {
      "text": "我因為肚子餓，所以想吃飯。",
      "pinyin": "Wǒ yīnwèi dùzi è, suǒyǐ xiǎng chī fàn.",
      "pinyin_numeric": "wo3 yin1 wei4 du4 zi0 e4, suo3 yi3 xiang3 chi1 fan4",
      "translation_en": "I want to eat because I'm hungry.",
      "translation_ko": "배가 고파서 밥을 먹고 싶어요."
    },
    {
      "text": "他為什麼不想喝咖啡？",
      "pinyin": "Tā wèishénme bù xiǎng hē kāfēi?",
      "pinyin_numeric": "ta1 wei4 shen2 me0 bu4 xiang3 he1 ka1 fei1",
      "translation_en": "Why doesn't he want to drink coffee?",
      "translation_ko": "그는 왜 커피를 마시고 싶지 않나요?"
    },
    {
      "text": "因為他口渴，所以想喝水。",
      "pinyin": "Yīnwèi tā kǒukě, suǒyǐ xiǎng hē shuǐ.",
      "pinyin_numeric": "yin1 wei4 ta1 kou3 ke3, suo3 yi3 xiang3 he1 shui3",
      "translation_en": "Because he is thirsty, he wants to drink water.",
      "translation_ko": "그는 목이 말라서 물을 마시고 싶어요."
    },
    {
      "text": "你為什麼不想買這個？",
      "pinyin": "Nǐ wèishénme bù xiǎng mǎi zhège?",
      "pinyin_numeric": "ni3 wei4 shen2 me0 bu4 xiang3 mai3 zhe4 ge0",
      "translation_en": "Why don't you want to buy this?",
      "translation_ko": "왜 이것을 사고 싶지 않으세요?"
    },
    {
      "text": "因為太貴了，所以我不想買。",
      "pinyin": "Yīnwèi tài guì le, suǒyǐ wǒ bù xiǎng mǎi.",
      "pinyin_numeric": "yin1 wei4 tai4 gui4 le0, suo3 yi3 wo3 bu4 xiang3 mai3",
      "translation_en": "Because it's too expensive, I don't want to buy it.",
      "translation_ko": "너무 비싸서 사고 싶지 않아요."
    },
    {
      "text": "她為什麼想休息？",
      "pinyin": "Tā wèishénme xiǎng xiūxí?",
      "pinyin_numeric": "ta1 wei4 shen2 me0 xiang3 xiu1 xi2",
      "translation_en": "Why does she want to rest?",
      "translation_ko": "그녀는 왜 쉬고 싶어 하나요?"
    },
    {
      "text": "因為她太累了，所以想休息。",
      "pinyin": "Yīnwèi tā tài lèi le, suǒyǐ xiǎng xiūxí.",
      "pinyin_numeric": "yin1 wei4 ta1 tai4 lei4 le0, suo3 yi3 xiang3 xiu1 xi2",
      "translation_en": "Because she is too tired, she wants to rest.",
      "translation_ko": "그녀는 너무 피곤해서 쉬고 싶어요."
    },
    {
      "text": "你為什麼不想去？",
      "pinyin": "Nǐ wèishénme bù xiǎng qù?",
      "pinyin_numeric": "ni3 wei4 shen2 me0 bu4 xiang3 qu4",
      "translation_en": "Why don't you want to go?",
      "translation_ko": "왜 가고 싶지 않으세요?"
    },
    {
      "text": "因為太遠了，所以我不想走路去。",
      "pinyin": "Yīnwèi tài yuǎn le, suǒyǐ wǒ bù xiǎng zǒulù qù.",
      "pinyin_numeric": "yin1 wei4 tai4 yuan3 le0, suo3 yi3 wo3 bu4 xiang3 zou3 lu4 qu4",
      "translation_en": "Because it's too far, I don't want to walk there.",
      "translation_ko": "너무 멀어서 걸어가고 싶지 않아요."
    }
  ]
}
